#!/usr/bin/env node
/**
 * Patch the npm/<triple>/package.json files generated by
 * `napi create-npm-dirs` so that:
 *
 *   1. `publishConfig.access` is "public" — npm treats scoped packages as
 *      private by default and refuses to publish without this.
 *   2. `description` matches the root package.json (napi's default
 *      description lags behind the curated copy in the root and goes stale
 *      when platform coverage changes).
 *
 * Wired up via the `postcreate-npm-dirs` script hook in package.json —
 * npm and Bun both run `post<hook>` automatically after the matching
 * `npm run create-npm-dirs`. The script is idempotent: re-running it on
 * already-patched package.json files is a no-op aside from formatting.
 */
import { readdirSync, readFileSync, writeFileSync, statSync } from 'node:fs'
import { join, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'

const here = dirname(fileURLToPath(import.meta.url))
const repoRoot = dirname(here)
const npmDir = join(repoRoot, 'npm')
const rootPkgPath = join(repoRoot, 'package.json')

const rootPkg = JSON.parse(readFileSync(rootPkgPath, 'utf8'))
const rootDescription = rootPkg.description ?? ''
const rootPublishConfig = rootPkg.publishConfig ?? { access: 'public' }

let entries
try {
    entries = readdirSync(npmDir)
} catch (err) {
    if (err.code === 'ENOENT') {
        // npm/ doesn't exist yet — nothing to patch.
        process.exit(0)
    }
    throw err
}

let patched = 0
for (const name of entries) {
    const dir = join(npmDir, name)
    if (!statSync(dir).isDirectory()) continue
    const pkgPath = join(dir, 'package.json')
    let pkg
    try {
        pkg = JSON.parse(readFileSync(pkgPath, 'utf8'))
    } catch {
        continue
    }

    let changed = false

    // 1. publishConfig.access === 'public' (required for scoped packages).
    const currentAccess = pkg.publishConfig?.access
    if (currentAccess !== 'public') {
        pkg.publishConfig = { ...(pkg.publishConfig ?? {}), ...rootPublishConfig }
        if (pkg.publishConfig.access !== 'public') {
            pkg.publishConfig.access = 'public'
        }
        changed = true
    }

    // 2. Keep the description in sync with the root (hand-curated).
    if (rootDescription && pkg.description !== rootDescription) {
        pkg.description = rootDescription
        changed = true
    }

    if (changed) {
        writeFileSync(pkgPath, JSON.stringify(pkg, null, 2) + '\n')
        patched++
    }
}

if (patched > 0) {
    console.log(`patch-npm-dirs: updated ${patched} package.json file(s) under npm/`)
} else {
    console.log('patch-npm-dirs: nothing to patch')
}